-- BOVISION AI Database Schema\n-- This file contains the database structure and sample data\n\nCREATE DATABASE IF NOT EXISTS bovision_ai;\nUSE bovision_ai;\n\nCREATE TABLE IF NOT EXISTS users (\n  id VARCHAR(36) PRIMARY KEY,\n  email VARCHAR(255) UNIQUE NOT NULL,\n  name VARCHAR(255) NOT NULL,\n  role ENUM('admin', 'user') DEFAULT 'user',\n  pin_hash VARCHAR(255),\n  device_id VARCHAR(255),\n  created_at BIGINT NOT NULL,\n  updated_at BIGINT NOT NULL\n);\n\nCREATE TABLE IF NOT EXISTS devices (\n  id VARCHAR(36) PRIMARY KEY,\n  user_id VARCHAR(36) NOT NULL,\n  device_id VARCHAR(255) UNIQUE NOT NULL,\n  created_at BIGINT NOT NULL,\n  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE\n);\n\nCREATE TABLE IF NOT EXISTS animals (\n  id VARCHAR(36) PRIMARY KEY,\n  user_id VARCHAR(36) NOT NULL,\n  name VARCHAR(255) NOT NULL,\n  breed VARCHAR(255),\n  age INT,\n  weight DECIMAL(10, 2),\n  health_score INT,\n  last_weight_date BIGINT,\n  created_at BIGINT NOT NULL,\n  updated_at BIGINT NOT NULL,\n  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE\n);\n\nCREATE TABLE IF NOT EXISTS health_records (\n  id VARCHAR(36) PRIMARY KEY,\n  animal_id VARCHAR(36) NOT NULL,\n  temperature DECIMAL(5, 2),\n  heart_rate INT,\n  respiratory_rate INT,\n  notes TEXT,\n  recorded_at BIGINT NOT NULL,\n  created_at BIGINT NOT NULL,\n  FOREIGN KEY (animal_id) REFERENCES animals(id) ON DELETE CASCADE\n);\n\nCREATE TABLE IF NOT EXISTS vaccinations (\n  id VARCHAR(36) PRIMARY KEY,\n  animal_id VARCHAR(36) NOT NULL,\n  vaccine_name VARCHAR(255),\n  vaccination_date BIGINT NOT NULL,\n  next_dose_date BIGINT,\n  notes TEXT,\n  created_at BIGINT NOT NULL,\n  FOREIGN KEY (animal_id) REFERENCES animals(id) ON DELETE CASCADE\n);\n\nCREATE TABLE IF NOT EXISTS financial (\n  id VARCHAR(36) PRIMARY KEY,\n  user_id VARCHAR(36) NOT NULL,\n  type ENUM('income', 'expense') NOT NULL,\n  category VARCHAR(255),\n  amount DECIMAL(12, 2),\n  description TEXT,\n  date BIGINT NOT NULL,\n  created_at BIGINT NOT NULL,\n  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE\n);\n\nCREATE TABLE IF NOT EXISTS conversations (\n  id VARCHAR(36) PRIMARY KEY,\n  user_id VARCHAR(36) NOT NULL,\n  title VARCHAR(255),\n  created_at BIGINT NOT NULL,\n  updated_at BIGINT NOT NULL,\n  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE\n);\n\nCREATE TABLE IF NOT EXISTS conversation_messages (\n  id VARCHAR(36) PRIMARY KEY,\n  conversation_id VARCHAR(36) NOT NULL,\n  role VARCHAR(50),\n  content TEXT,\n  created_at BIGINT NOT NULL,\n  FOREIGN KEY (conversation_id) REFERENCES conversations(id) ON DELETE CASCADE\n);\n\nCREATE INDEX idx_users_email ON users(email);\nCREATE INDEX idx_animals_user_id ON animals(user_id);\nCREATE INDEX idx_health_records_animal_id ON health_records(animal_id);\nCREATE INDEX idx_vaccinations_animal_id ON vaccinations(animal_id);\nCREATE INDEX idx_financial_user_id ON financial(user_id);\nCREATE INDEX idx_conversations_user_id ON conversations(user_id);\nCREATE INDEX idx_conversation_messages_conversation_id ON conversation_messages(conversation_id);
